```cpp
#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>
#include <span>
#include <string_view>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;
};

NetworkPacket deserialize_packet(const std::span<const uint8_t> buffer) {
    // Wrap the provided read-only span in a Hexi buffer adaptor and stream
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    NetworkPacket packet{};

    // 1. Read packet_id (plain 32-bit unsigned integer)
    stream(packet.packet_id);

    // 2. Read username using length prefix
    // Assuming standard Hexi "prefixed" string style: first a length, then bytes.
    // Read the length, then a zero-copy view of that region, then copy into std::string.
    uint32_t username_len{};
    stream(username_len);

    // Get a zero-copy span over the username bytes
    auto username_span = stream.span<char>(username_len);
    packet.username.assign(username_span.data(), username_span.size());

    // 3. Read score count, then read scores vector
    uint32_t score_count{};
    stream(score_count);

    // Prepare the vector and use read_container for the elements
    packet.scores.resize(score_count);
    stream.read_container(packet.scores);

    // 4. Read metadata as null-terminated string for zero-copy
    // Use Hexi's cstring-like support to grab up to the null terminator,
    // then copy into the std::string.
    auto metadata_view = stream.cstring_view();
    packet.metadata.assign(metadata_view.data(), metadata_view.size());

    // 5. Skip any remaining padding bytes (if any)
    // Advance the read pointer to the end of the underlying buffer.
    auto remaining = adaptor.size() - adaptor.read_pos();
    if (remaining > 0) {
        stream.skip(remaining);
    }

    return packet;
}

struct PacketInfo {
    uint32_t packet_id;
    std::string_view username;
};

PacketInfo extract_packet_info(const std::span<const uint8_t> buffer) {
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    PacketInfo info{};

    // 1. Use span() to get a zero-copy view of the packet_id (first 4 bytes)
    auto id_span = stream.span<std::uint8_t>(sizeof(std::uint32_t));
    // Interpret as little-endian uint32_t (Hexi typically works in native endianness;
    // here we just memcpy for safety).
    std::uint32_t packet_id{};
    std::memcpy(&packet_id, id_span.data(), sizeof(packet_id));
    info.packet_id = packet_id;

    // 2. Read username using prefixed adaptor to get a string_view
    uint32_t username_len{};
    stream(username_len);
    auto username_span = stream.span<char>(username_len);
    info.username = std::string_view(username_span.data(), username_span.size());

    // 3. Skip the scores vector without reading its elements
    // First read the count, then skip count * sizeof(uint32_t) bytes.
    uint32_t score_count{};
    stream(score_count);

    std::size_t scores_bytes = static_cast<std::size_t>(score_count) * sizeof(uint32_t);
    stream.skip(scores_bytes);

    // We intentionally do not read metadata here.

    return info;
}
