};

MessageHeader read_header_and_skip_body(const std::span<const uint8_t> buffer) {
    // Adapt the read-only span into a Hexi buffer
    hexi::buffer_adaptor adaptor(buffer);

    // Create a binary_stream for reading
    hexi::binary_stream stream(adaptor);

    MessageHeader header{};

    // Read message_type (uint16_t)
    stream.get(header.message_type);

    // Read body_length (uint32_t)
    stream.get(header.body_length);

    // Skip the body_data using the length we just read
    stream.skip(header.body_length);

    // Read footer (uint32_t)
    stream.get(header.footer);

    return header;
}
