	hexi::buffer_adaptor adaptor(buffer);

	// Create a binary_stream for reading
	hexi::binary_stream stream(adaptor);

	// Read the item count (uint32_t)
	std::uint32_t item_count{};
	stream >> item_count;

	// Prepare the container with the correct size
	std::vector<std::uint32_t> items(item_count);

	// Use Hexi's container-reading support (read_container) via operator>>
	stream >> items;

	return items;
}
