```cpp
#include <hexi/hexi.h>
#include <vector>
#include <cstdint>
#include <algorithm> // for std::min

std::vector<uint8_t> read_buffer_data(const std::vector<uint8_t>& source_buffer, size_t bytes_to_read) {
    // Limit read size to what is actually available
    const std::size_t to_read = std::min<std::size_t>(bytes_to_read, source_buffer.size());

    // Create an adaptor over the read-only buffer
    hexi::buffer_adaptor adaptor(source_buffer);
    hexi::binary_stream stream(adaptor);

    std::vector<std::uint8_t> result(to_read);
    if (to_read > 0) {
        stream.read(result.data(), to_read);
    }

    return result;
}

void write_buffer_data(std::vector<uint8_t>& dest_buffer, const std::vector<uint8_t>& source_data) {
    // Ensure the destination has enough space
    const std::size_t to_write = source_data.size();
    if (to_write == 0) {
        return;
    }

    dest_buffer.resize(to_write);

    // Create an adaptor over the writable buffer
    hexi::buffer_adaptor adaptor(dest_buffer);
    hexi::binary_stream stream(adaptor);

    stream.write(source_data.data(), to_write);
}
```

