#include <hexi/hexi.h>
#include <vector>
#include <cstdint>
#include <algorithm>

std::vector<uint8_t> peek_buffer_data(const std::vector<uint8_t>& buffer, size_t bytes_to_peek) {
    // Create a buffer_adaptor over the input buffer. Since the buffer is const,
    // this will be a read-only adaptor, which is fine for peeking.
    hexi::buffer_adaptor adaptor(buffer);

    // Determine how many bytes we can actually peek (can't exceed buffer size).
    const auto available = adaptor.size();
    const auto to_copy = std::min<std::size_t>(bytes_to_peek, available);

    // Prepare the destination vector.
    std::vector<uint8_t> result(to_copy);

    // Use copy() to read without advancing the adaptor's read cursor.
    if (to_copy > 0) {
        adaptor.copy(result.data(), to_copy);
    }

    return result;
}
