```cpp
#include <hexi/hexi.h>
#include <vector>
#include <cstdint>
#include <cstddef>

const uint8_t* get_read_pointer(const std::vector<uint8_t>& buffer) {
    // Use Hexi's buffer_adaptor to obtain the logical read pointer
    hexi::buffer_adaptor adaptor(buffer);
    // data() on the adaptor gives us the current read position
    return reinterpret_cast<const uint8_t*>(adaptor.data());
}

uint8_t* get_write_pointer(std::vector<uint8_t>& buffer) {
    // Use Hexi's buffer_adaptor to obtain the logical write pointer
    hexi::buffer_adaptor adaptor(buffer);

    // buffer_adaptor operates over an existing container's storage.
    // The "write pointer" corresponds to begin() + current write offset.
    // We can get that by taking the underlying data() and adding the adaptor's size().
    // Note: adaptor.size() == number of readable bytes (write_offset - read_offset),
    // and read position is adaptor.data(), so write position is:
    //    write_ptr = read_ptr + size()
    auto* read_ptr = reinterpret_cast<uint8_t*>(adaptor.data());
    return read_ptr + adaptor.size();
}

struct BufferInfo {
    size_t readable_size;
    size_t free_space;
};

BufferInfo check_buffer_space(const std::vector<uint8_t>& buffer) {
    hexi::buffer_adaptor adaptor(buffer);

    BufferInfo info{};
    // Readable bytes from current read pointer to write pointer
    info.readable_size = adaptor.size();

    // Free space is the remaining capacity in the underlying vector
    // from the current write position to the end of allocated storage.
    // Hexi's adaptor does not track capacity itself, so we use the container's
    // capacity minus the logical write offset.
    //
    // Logical write offset = distance from underlying data() to write pointer.
    // From get_write_pointer we know:
    //   write_ptr = read_ptr + adaptor.size()
