    uint8_t data_type;
    std::vector<uint32_t> int_items;
    std::vector<float> float_items;
};

DataResult preview_and_read_data(const std::span<const uint8_t> buffer) {
    DataResult result{};

    // Create an adaptor/stream over the read‑only span
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Preview first byte (data_type) without advancing the read pointer.
    // binary_stream provides random access via operator[], which does not
    // change the internal read offset.
    std::byte previewed{};
    if (buffer.size() >= 1) {
        previewed = stream[0];
    } else {
        // Not enough data even for the type byte; return default result
        return result;
    }

    result.data_type = static_cast<uint8_t>(previewed);

    // Now actually read data_type and item_count from the stream
    uint8_t data_type{};
    uint32_t item_count{};

    stream >> data_type >> item_count;

    // If stream already failed (e.g., not enough bytes), return whatever we have
    if (!stream) {
        return result;
    }

    // Check that the remaining data in the buffer is large enough to hold all items
    const std::size_t header_size = sizeof(data_type) + sizeof(item_count); // 1 + 4
    const std::size_t remaining_bytes = buffer.size() > header_size
                                        ? buffer.size() - header_size
                                        : 0;

    std::size_t bytes_per_item = 0;
    switch (data_type) {
    case 0: // integers
        bytes_per_item = sizeof(uint32_t);
        break;
    case 1: // floats
        bytes_per_item = sizeof(float);
        break;
    default:
        // Unknown data type; just return the previewed type
        return result;
    }

    // If not enough bytes for all items, clamp item_count to what we can safely read
    const std::size_t max_items_by_size =
        bytes_per_item == 0 ? 0 : (remaining_bytes / bytes_per_item);
    if (item_count > max_items_by_size) {
        item_count = static_cast<uint32_t>(max_items_by_size);
    }

    // Read the items based on the data type
    if (data_type == 0) {
        result.int_items.resize(item_count);
        for (uint32_t i = 0; i < item_count; ++i) {
            stream >> result.int_items[i];
            if (!stream) {
                // Truncate on failure
                result.int_items.resize(i);
                break;
            }
        }
    } else if (data_type == 1) {
        result.float_items.resize(item_count);
        for (uint32_t i = 0; i < item_count; ++i) {
            stream >> result.float_items[i];
            if (!stream) {
                // Truncate on failure
                result.float_items.resize(i);
                break;
            }
        }
    }

    // Store the final type we actually read
    result.data_type = data_type;
    return result;
}

