```cpp
#include <hexi/hexi.h>
#include <vector>
#include <cstdint>

bool write_data_with_check(std::vector<uint8_t>& buffer, uint32_t header, const std::vector<uint32_t>& items) {
    using byte = std::uint8_t;

    // Calculate required size:
    // - header: uint32_t
    // - items: written via write_container (typically size + elements as uint32_t)
    const std::size_t header_size = sizeof(std::uint32_t);
    const std::size_t count_size  = sizeof(std::uint32_t);                  // container size field
    const std::size_t items_size  = items.size() * sizeof(std::uint32_t);   // all elements
    const std::size_t required    = header_size + count_size + items_size;

    // If buffer is too small, fail
    if (buffer.size() < required) {
        return false;
    }

    // Adapt the existing buffer
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor, hexi::no_throw); // avoid exceptions, use state instead

    // Limit writing to the available space
    // (binary_stream will respect buffer size; we're just being explicit)
    if (adaptor.write_remaining() < required) {
        return false;
    }

    // Write data
    stream << header;
    stream.write_container(items);

    // Check if stream is still in a good state (no overflow or other errors)
    return static_cast<bool>(stream);
}
