```cpp
#include <hexi/hexi.h>
#include <cstdint>
#include <span>

struct PacketHeader {
    uint32_t magic;
    uint16_t version;
    uint16_t flags;
};

PacketHeader read_header_with_span(const std::span<const uint8_t> buffer) {
    // Adapt the read-only span into a Hexi buffer
    hexi::buffer_adaptor adaptor(buffer);

    // Create a binary_stream on top of the adaptor
    hexi::binary_stream stream(adaptor);

    // Get the current read pointer and available size from the adaptor
    auto read_ptr   = adaptor.read_ptr();
    auto read_avail = adaptor.read_available();

    // The header is 8 bytes in total
    constexpr std::size_t header_size =
        sizeof(std::uint32_t) + sizeof(std::uint16_t) + sizeof(std::uint16_t);

    // Check we have enough data to read the header
    if (read_avail < header_size) {
        throw std::runtime_error("Not enough data to read PacketHeader");
    }

    // Use binary_stream's zero-copy facility to get a span over the header bytes.
    // This assumes Hexi exposes a zero-copy read into std::span<std::byte> / std::span<const std::byte>.
    std::span<const std::byte> header_span{};
    stream.view(header_span, header_size); // zero-copy: does not copy header bytes

    // Now interpret the header_span as three fields. We avoid undefined behavior by
    // copying each field out with std::memcpy rather than reinterpreting the buffer.
    PacketHeader header{};
    const auto* data = header_span.data();

    std::memcpy(&header.magic,   data,                                  sizeof(header.magic));
    std::memcpy(&header.version, data + sizeof(header.magic),           sizeof(header.version));
    std::memcpy(&header.flags,   data + sizeof(header.magic) +
                                           sizeof(header.version),      sizeof(header.flags));

    return header;
}
```

