#include <hexi/hexi.h>
#include <cstdint>
#include <span>
#include <string_view>

struct MessagePacket {
    uint32_t header;
    std::string_view message;
};

MessagePacket read_header_and_message(const std::span<const uint8_t> buffer) {
    // Adapt the provided span into a Hexi buffer_adaptor
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Read the header
    uint32_t header{};
    stream >> header;

    // Get a view into the remaining buffer from the current read position
    auto remaining = stream.view<std::span<const uint8_t>>();

    // Find the null terminator within the remaining data
    std::size_t len = 0;
    while (len < remaining.size() && remaining[len] != 0) {
        ++len;
    }

    // Construct a string_view over the bytes up to (but not including) the null
    // Note: reinterpret_cast is safe here as we're treating bytes as chars
    const char* msg_ptr = reinterpret_cast<const char*>(remaining.data());
    std::string_view message(msg_ptr, len);

    return MessagePacket{header, message};
}
