```cpp
#include <hexi/dynamic_buffer.h>
#include <vector>
#include <cstdint>
#include <cstddef>

template<size_t block_size = 1024>
std::vector<uint8_t> peek_data_from_buffer(const hexi::dynamic_buffer<block_size>& buffer,
                                           size_t bytes_to_peek) {
    // Clamp to available readable bytes
    const auto available = buffer.read_size();
    if (bytes_to_peek > available) {
        bytes_to_peek = available;
    }

    std::vector<uint8_t> out(bytes_to_peek);
    if (bytes_to_peek == 0) {
        return out;
    }

    // dynamic_buffer exposes operator[] for random access to readable bytes
    // without moving the internal read cursor. We copy directly from it.
    for (size_t i = 0; i < bytes_to_peek; ++i) {
        out[i] = static_cast<uint8_t>(buffer[i]);
    }

    return out;
}
```

