```cpp
#include <hexi/allocators/block_allocator.h>
#include <cstdint>
#include <array>
#include <iostream>

// Note: push() and pop() are private, but we can observe their behavior
// through allocate() and deallocate() operations
template<size_t element_count = 10>
void demonstrate_block_allocator_behavior() {
    using value_type = std::uint64_t;
    using allocator_type = hexi::block_allocator<value_type, element_count>;

    allocator_type alloc;

    std::cout << "=== block_allocator free list behavior demo ===\n";
    std::cout << "element_count = " << element_count << "\n\n";

    // 1) Allocate all elements once.
    //    Internally, each allocate() will pop() from the free list.
    std::array<value_type*, element_count> ptrs{};
    std::cout << "First pass: allocate() " << element_count
              << " times (pop from free list)\n";

    for (std::size_t i = 0; i < element_count; ++i) {
        ptrs[i] = alloc.allocate();
        std::cout << "  allocate() -> " << static_cast<void*>(ptrs[i]) << '\n';
    }

    std::cout << "\nAt this point, the internal free list is empty.\n\n";

    // 2) Deallocate them in forward order.
    //    Each deallocate() will push() the block back to the head of the free list.
    std::cout << "Deallocate in forward order (push to free list head):\n";
    for (std::size_t i = 0; i < element_count; ++i) {
        std::cout << "  deallocate(" << static_cast<void*>(ptrs[i]) << ")\n";
        alloc.deallocate(ptrs[i]);
    }

    std::cout << "\nNow the free list contains all blocks again.\n"
                 "Because each deallocation pushes to the head,\n"
                 "the most recently deallocated block will be popped first.\n\n";

    // 3) Allocate again to show LIFO behavior of the free list.
    std::cout << "Second pass: allocate() again (observe LIFO order):\n";
    for (std::size_t i = 0; i < element_count; ++i) {
        auto* p = alloc.allocate();
        std::cout << "  allocate() -> " << static_cast<void*>(p)
                  << " (should be in reverse order of last deallocations)\n";
    }

    std::cout << "\nThis demonstrates that internally:\n"
                 "  - allocate() uses pop() from the free list head\n"
                 "  - deallocate() uses push() to the free list head\n"
                 "resulting in a LIFO (stack-like) free list.\n";
}
```

