template<std::endian from, std::endian to, typename T>
T convert_endianness(T value) {
    // Delegate to Hexi's compile‑time conditional endianness conversion
    if constexpr (from == to) {
        return value;
    } else {
        return hexi::conditional_reverse<from, to>(value);
    }
}

template<typename T>
T convert_endianness_runtime(T value, std::endian from, std::endian to) {
    // If endianness is the same, no conversion is needed
    if (from == to) {
        return value;
    }

    // Dispatch to the compile‑time version using Hexi's facilities
    switch (from) {
        case std::endian::little:
            switch (to) {
                case std::endian::little:
                    return value; // already handled above, but keep for completeness
                case std::endian::big:
                    return convert_endianness<std::endian::little,
                                             std::endian::big>(value);
                case std::endian::native:
                    return convert_endianness<std::endian::little,
                                             std::endian::native>(value);
            }
            break;

        case std::endian::big:
            switch (to) {
                case std::endian::little:
                    return convert_endianness<std::endian::big,
                                             std::endian::little>(value);
                case std::endian::big:
                    return value; // already handled above
                case std::endian::native:
                    return convert_endianness<std::endian::big,
                                             std::endian::native>(value);
            }
            break;

        case std::endian::native:
            switch (to) {
                case std::endian::little:
                    return convert_endianness<std::endian::native,
                                             std::endian::little>(value);
                case std::endian::big:
                    return convert_endianness<std::endian::native,
                                             std::endian::big>(value);
                case std::endian::native:
                    return value; // already handled above
            }
            break;
    }

    // Fallback (should be unreachable with the standard endianness values)
    return value;
}
