#include <hexi/detail/intrusive_storage.h>
#include <vector>
#include <cstdint>
#include <algorithm> // for std::min
#include <cstddef>   // for std::byte
#include <type_traits>

template<std::size_t block_size = 1024>
std::vector<uint8_t> preview_data_without_consuming(
    const hexi::detail::intrusive_storage<block_size>& storage,
    std::size_t bytes_to_preview
) {
    // Compute how many bytes are actually readable.
    const std::size_t readable =
        (storage.write_offset > storage.read_offset)
            ? static_cast<std::size_t>(storage.write_offset - storage.read_offset)
            : 0;

    const std::size_t to_copy = std::min(readable, bytes_to_preview);

    std::vector<uint8_t> result;
    result.reserve(to_copy);

    // storage.storage is an array of value_type, which defaults to std::byte.
    // We need to convert each element to uint8_t.
    for (std::size_t i = 0; i < to_copy; ++i) {
        const auto& v = storage.storage[storage.read_offset + i];

        if constexpr (std::is_same_v<typename hexi::detail::intrusive_storage<block_size>::value_type, std::byte>) {
            result.push_back(static_cast<uint8_t>(v));
        } else {
            result.push_back(static_cast<uint8_t>(v));
        }
    }

    return result;
}

template<std::size_t block_size = 1024>
struct BufferStatus {
    std::size_t readable_size;
    std::size_t free_space;
};

inline BufferStatus<> check_buffer_status(const hexi::detail::intrusive_storage<1024>& storage) {
    BufferStatus<> status{};

    // readable_size is how much data is between read_offset and write_offset
    if (storage.write_offset > storage.read_offset) {
        status.readable_size =
            static_cast<std::size_t>(storage.write_offset - storage.read_offset);
    } else {
        status.readable_size = 0;
    }

    // free_space is how much room is left in the storage array from write_offset
    status.free_space =
        (storage.write_offset < 1024)
            ? static_cast<std::size_t>(1024 - storage.write_offset)
            : 0;

    return status;
}

template<std::size_t block_size = 1024>
void reset_buffer(hexi::detail::intrusive_storage<block_size>& storage) {
    // Use the provided clear() method, which resets read and write offsets.
    storage.clear();
}
