#include <hexi/file_buffer.h>
#include <vector>
#include <cstdint>
#include <filesystem>

std::vector<uint8_t> read_file_data(const std::filesystem::path& file_path, size_t bytes_to_read) {
    // Open file buffer in read mode
    hexi::file_buffer buffer(file_path);

    // Determine how many bytes we can actually read
    const std::size_t available = buffer.size();
    const std::size_t to_read   = std::min<std::size_t>(bytes_to_read, available);

    std::vector<std::uint8_t> out(to_read);
    if (to_read > 0) {
        buffer.read(out.data(), to_read);
    }

    return out;
}

std::vector<uint8_t> preview_file_data(const std::filesystem::path& file_path, size_t bytes_to_preview) {
    // Open file buffer in read mode
    hexi::file_buffer buffer(file_path);

    // Determine how many bytes we can actually preview
    const std::size_t available = buffer.size();
    const std::size_t to_preview = std::min<std::size_t>(bytes_to_preview, available);

    std::vector<std::uint8_t> out(to_preview);
    if (to_preview == 0) {
        return out;
    }

    // Save current read position, copy the data, then restore position.
    // file_buffer provides copy() which does not advance the read pointer.
    buffer.copy(out.data(), to_preview);

    return out;
}

void write_file_data(const std::filesystem::path& file_path, const std::vector<uint8_t>& data) {
    // Open file buffer in write mode. The file_buffer constructor taking a path
    // typically opens for read/write; we then use write() to append/overwrite
    // from the current write position (usually beginning for a new file).
    hexi::file_buffer buffer(file_path, hexi::file_mode::write);

    if (!data.empty()) {
        buffer.write(data.data(), data.size());
    }
}

size_t get_file_size(const std::filesystem::path& file_path) {
    hexi::file_buffer buffer(file_path);
    return buffer.size();
}
