    std::filesystem::path test_file = "test_size.bin";
    size_t expected_size = 100;
    create_test_file(test_file, expected_size);

    size_t file_size = get_file_readable_size(test_file);

    EXPECT_EQ(expected_size, file_size);

    std::filesystem::remove(test_file);
}

TEST(FileBuffer, GetEmptyFileSize) {
    std::filesystem::path test_file = "test_empty.bin";
    create_test_file(test_file, 0);

    size_t file_size = get_file_readable_size(test_file);

    EXPECT_EQ(0, file_size);

    std::filesystem::remove(test_file);
}

