```cpp
#include <hexi/file_buffer.h>
#include <filesystem>

size_t get_file_readable_size(const std::filesystem::path& file_path) {
    // Open the file in binary read mode
    hexi::file_buffer fb(file_path.string().c_str(), "rb");

    // If opening failed, report zero readable size
    if (!fb) {
        return 0;
    }

    // hexi::file_buffer exposes a size() member giving the file size
    return fb.size();
}

bool is_file_buffer_valid(const std::filesystem::path& file_path) {
    // Attempt to open the file; validity can be checked via operator bool
    hexi::file_buffer fb(file_path.string().c_str(), "rb");
    return static_cast<bool>(fb);
}
```

