```cpp
#include <hexi/file_buffer.h>
#include <hexi.h>              // for hexi::binary_stream, hexi::no_throw
#include <vector>
#include <cstdint>
#include <filesystem>
#include <algorithm>           // std::min

std::vector<uint8_t> preview_file_header(const std::filesystem::path& file_path,
                                         size_t header_size) {
    // Open file buffer (read-only by default)
    hexi::file_buffer fb(file_path.string().c_str());

    // Wrap in a no-throw binary_stream so we can inspect state()
    hexi::binary_stream stream(fb, hexi::no_throw);

    // Save current read position
    const auto original_pos = fb.read_position();

    // Prepare destination buffer
    std::vector<uint8_t> header(header_size, 0);

    // Determine how many bytes we can actually read
    const auto file_size   = fb.size();
    const auto remaining   =
        (original_pos < file_size) ? (file_size - original_pos) : 0;
    const auto to_read     = std::min<std::size_t>(header_size, remaining);

    if (to_read > 0) {
        // Read up to to_read bytes into header
        stream.read(reinterpret_cast<char*>(header.data()), to_read);
    }

    // Restore read position so we do not advance the read pointer
    fb.set_read_position(original_pos);

    // Optionally shrink vector if file shorter than requested header_size
    if (to_read < header_size) {
        header.resize(to_read);
    }

    return header;
}
```

