```cpp
#include <hexi/static_buffer.h>
#include <vector>
#include <cstdint>
#include <cstddef>

template<size_t buffer_size = 1024>
void write_data_to_buffer(hexi::static_buffer<std::byte, buffer_size>& buffer,
                          const std::vector<uint8_t>& data) {
    if (data.empty()) {
        return;
    }

    // The static_buffer interface provides a write() function taking (const void*, std::size_t)
    // like dynamic_buffer does elsewhere in the library/tests.
    buffer.write(static_cast<const void*>(data.data()), data.size());
}

template<size_t buffer_size = 1024>
std::vector<uint8_t> read_data_from_buffer(hexi::static_buffer<std::byte, buffer_size>& buffer,
                                           size_t bytes_to_read) {
    std::vector<uint8_t> result;
    if (bytes_to_read == 0) {
        return result;
    }

    result.resize(bytes_to_read);

    // Read into the underlying uint8_t storage via void* pointer.
    buffer.read(static_cast<void*>(result.data()), bytes_to_read);

    return result;
}
```

