output.text:
```cpp
#include <hexi/static_buffer.h>

template<size_t buffer_size = 1024>
struct BufferInfo {
    size_t capacity;      // total capacity of the buffer
    size_t current_size;  // current readable data size
    size_t free_space;    // remaining writable space
};

BufferInfo<> get_buffer_info(const hexi::static_buffer<std::byte, 1024>& buffer) {
    BufferInfo<> info{};

    // Total capacity is the compile-time size of the static_buffer
    info.capacity = buffer.size();

    // Current readable size is the difference between write and read offsets
    const auto read_pos  = buffer.read_offset();
    const auto write_pos = buffer.write_offset();

    info.current_size = (write_pos >= read_pos)
        ? (write_pos - read_pos)
        : 0; // safety fallback; should not normally happen

    // Free space is total capacity minus used (readable) size
    info.free_space = (info.capacity >= info.current_size)
        ? (info.capacity - info.current_size)
        : 0; // safety fallback

    return info;
}
```

