```cpp
#include <hexi/static_buffer.h>
#include <vector>
#include <cstdint>
#include <cstddef>
#include <algorithm>

template<size_t buffer_size = 1024>
std::vector<uint8_t> preview_buffer_data(const hexi::static_buffer<std::byte, buffer_size>& buffer,
                                         size_t bytes_to_preview)
{
    // We assume hexi::static_buffer exposes const buffer_read-style access:
    // - size(): number of readable bytes (write_ - read_)
    // - operator[](size_t): random access from current read position
    //
    // The function must *not* change the read pointer, so we only use
    // const, non-advancing operations.

    const std::size_t available = buffer.size();
    const std::size_t to_copy   = std::min<std::size_t>(available, bytes_to_preview);

    std::vector<uint8_t> out;
    out.reserve(to_copy);

    for (std::size_t i = 0; i < to_copy; ++i) {
        // Access as std::byte then convert to uint8_t
        out.push_back(static_cast<uint8_t>(buffer[i]));
    }

    return out;
}
```

