#include <hexi/pmc/binary_stream_writer.h>
#include <hexi/pmc/binary_stream_reader.h>
#include <hexi/pmc/buffer_adaptor.h>
#include <vector>
#include <cstdint>

struct UserData {
    uint32_t user_id;
    std::string name;

    void serialise(auto& stream) {
        // Hexi supports operator<< and operator>> on streams.
        // For writer, this will write; for reader, this will read.
        stream << user_id << name;
    }
};

void serialize_object(hexi::pmc::binary_stream_writer& writer, const UserData& data) {
    // Use the object's serialise method with the writer
    // to write its fields into the underlying buffer.
    const_cast<UserData&>(data).serialise(writer);
}

void deserialize_object(hexi::pmc::binary_stream_reader& reader, UserData& data) {
    // Use the same serialise method with the reader.
    // In Hexi, serialise can be symmetric if implemented with stream << and >>,
    // but the examples also show using operator() / &. Here we rely on << / >>.
    data.serialise(reader);
}
