#include <hexi/pmc/buffer_adaptor.h>
#include <string>

void write_string_to_stream(hexi::pmc::binary_stream_writer& writer, const std::string& str) {
    // Write the length of the string first (prefixed format),
    // then write the raw character data.
    const std::uint32_t size = static_cast<std::uint32_t>(str.size());
    writer.write(size);
    if (size > 0) {
        writer.write(str.data(), size);
    }
}

std::string read_string_from_stream(hexi::pmc::binary_stream_reader& reader) {
    // Read the length prefix, then read that many characters.
    std::uint32_t size = 0;
    reader.read(size);

    std::string result;
    result.resize(size);
    if (size > 0) {
        reader.read(result.data(), size);
    }

    return result;
}
