TEST(PMCBinaryStream, WriteReadContainer) {
    std::vector<std::byte> buffer(1000);
    hexi::pmc::buffer_adaptor adaptor(buffer, hexi::init_empty);

    hexi::pmc::buffer& buf_ref = adaptor;
    hexi::pmc::binary_stream_writer writer(static_cast<hexi::pmc::buffer_write&>(buf_ref));
    hexi::pmc::binary_stream_reader reader(static_cast<hexi::pmc::buffer_read&>(buf_ref));

    std::vector<uint32_t> original = {10, 20, 30, 40, 50};
    write_container_to_stream(writer, original);

    std::vector<uint32_t> result = read_container_from_stream(reader);

    EXPECT_EQ(original, result);
}

TEST(PMCBinaryStream, WriteReadLargeContainer) {
    std::vector<std::byte> buffer(10000);
    hexi::pmc::buffer_adaptor adaptor(buffer, hexi::init_empty);

    hexi::pmc::buffer& buf_ref = adaptor;
    hexi::pmc::binary_stream_writer writer(static_cast<hexi::pmc::buffer_write&>(buf_ref));
    hexi::pmc::binary_stream_reader reader(static_cast<hexi::pmc::buffer_read&>(buf_ref));

    std::vector<uint32_t> original(100, 42);
    write_container_to_stream(writer, original);

    std::vector<uint32_t> result = read_container_from_stream(reader);

    EXPECT_EQ(original.size(), result.size());
    EXPECT_EQ(original, result);
}

