```cpp
#include <hexi/pmc/buffer_adaptor.h>
#include <vector>
#include <cstdint>
#include <cstring>   // for std::memcpy
#include <limits>    // for std::numeric_limits

void write_data_to_buffer(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer,
                          uint32_t value,
                          const void* data,
                          std::size_t length) {
    // Write the 32-bit integer value in native endianness
    buffer.write(&value, sizeof(value));

    // Write the raw byte array
    if (length > 0 && data != nullptr) {
        buffer.write(data, length);
    }
}

void read_data_from_buffer(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer,
                           uint32_t& value,
                           void* data,
                           std::size_t length) {
    // Read the 32-bit integer value
    buffer.read(&value, sizeof(value));

    // Read the raw byte array
    if (length > 0 && data != nullptr) {
        buffer.read(data, length);
    }
}

struct BufferInfo {
    std::size_t size;        // number of bytes currently used / written
    std::size_t free_space;  // remaining capacity that can still be written
};

BufferInfo get_buffer_info(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer) {
    BufferInfo info{};

    // buffer.size() gives current used size
    info.size = buffer.size();

    // For std::vector-backed adaptor, we can compute free space
    // as underlying capacity minus current size, if exposed.
    // buffer.capacity() may not exist on adaptor, so we use the
    // underlying container via data().
    //
    // Here we assume buffer is wrapping a std::vector<std::byte>
    // and use its capacity via the adaptor API:
    //
    // If buffer has a capacity() method, use it; otherwise, fall
    // back to "unknown" free space.
    //
    // Since we don't have the exact interface here, we'll implement
    // a safe approximation: reserve(0) should not change capacity,
    // and if reserve is cheap, this gives us the remaining space
    // as max_size - size(). If max_size is not bounded, set
    // free_space to the maximum possible.

    // Try to get an upper bound on possible growth; for a std::vector
    // this is typically vector::max_size(), but the adaptor does not
    // expose it. We therefore treat free_space as "unbounded" from
    // the adaptor’s perspective.
    info.free_space = std::numeric_limits<std::size_t>::max() - info.size;

    return info;
}
