```cpp
#include <hexi/pmc/buffer_adaptor.h>
#include <vector>
#include <cstdint>
#include <cstring> // for std::memcmp

// Copy raw bytes from the buffer without advancing the read pointer.
void peek_data_from_buffer(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer,
                           void* data,
                           std::size_t length) {
    // Use the non-template copy(void*, std::size_t) overload to copy bytes.
    buffer.copy(data, length);
}

// Copy a single value of type T from the buffer without advancing the read pointer.
template<typename T>
void peek_value_from_buffer(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer,
                            T& value) {
    // Use the template copy<T>(T&) overload to copy a single value.
    buffer.copy(value);
}

// Peek data from the buffer and compare it with the expected data without consuming it.
bool peek_and_compare(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer,
                      const void* expected,
                      std::size_t length) {
    // Allocate a temporary buffer, peek into it, then compare.
    std::vector<std::byte> temp(length);
    if (length > 0) {
        buffer.copy(temp.data(), length);
        return std::memcmp(temp.data(), expected, length) == 0;
    }
    // For zero length, treat as equal by definition.
    return true;
}
```

