const void* get_read_pointer(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer) {
    // The read position of the adaptor is at index 0 of the readable region.
    // &buffer[0] is valid as long as the buffer isn't empty; for an empty buffer
    // we return nullptr to indicate there's no readable data.
    if (buffer.empty()) {
        return nullptr;
    }
    return static_cast<const void*>(&buffer[0]);
}

