    // 3) Seek back to the start and overwrite the header with the real value
    buffer.write_seek(hexi::buffer_seek::absolute, 0);

    std::byte header_bytes[sizeof(uint32_t)];
    std::memcpy(header_bytes, &header_value, sizeof(header_value));
    buffer.write(header_bytes, sizeof(header_bytes));

    // 4) Optionally seek to the end of written data so further writes append
    buffer.write_seek(hexi::buffer_seek::end, 0);
}

