```cpp
#include <hexi/shared.h>
#include <hexi/pmc/buffer_adaptor.h>
#include <hexi/pmc/binary_stream_writer.h>
#include <hexi/pmc/binary_stream_reader.h>
#include <vector>
#include <cstdint>
#include <type_traits>

using namespace hexi::detail;

// Simple unsigned LEB128-style varint for unsigned integers.
// For signed integers, we encode the value as its unsigned counterpart
// via std::make_unsigned_t and reinterpret on decode.

template<typename T>
std::size_t encode_varint(hexi::pmc::binary_stream_writer& writer, T value) {
    static_assert(std::is_integral_v<T>, "encode_varint requires an integral type");

    using U = std::make_unsigned_t<T>;
    U v = static_cast<U>(value);

    std::size_t bytes_written = 0;

    // LEB128-style: lower 7 bits per byte, MSB as continuation flag
    while (true) {
        std::uint8_t byte = static_cast<std::uint8_t>(v & 0x7Fu);
        v >>= 7;
        if (v != 0) {
            byte |= 0x80u; // set continuation bit
        }
        writer.write(byte);
        ++bytes_written;
        if (v == 0) {
            break;
        }
    }

    return bytes_written;
}

template<typename T>
T decode_varint(hexi::pmc::binary_stream_reader& reader) {
    static_assert(std::is_integral_v<T>, "decode_varint requires an integral type");

    using U = std::make_unsigned_t<T>;
    U result = 0;
    std::size_t shift = 0;

    while (true) {
        std::uint8_t byte = 0;
        reader.read(byte);

        U chunk = static_cast<U>(byte & 0x7Fu);
        result |= (chunk << shift);

        if ((byte & 0x80u) == 0) {
            break; // last byte
        }

        shift += 7;

        // Safety: avoid undefined behavior if shift exceeds bit-width
        if (shift >= sizeof(U) * 8) {
            // If the library supports setting stream state, we rely on it
            // having already transitioned to an error state on overflow;
            // here we just stop accumulating more bits.
            break;
        }
    }

    if constexpr (std::is_signed_v<T>) {
        return static_cast<T>(result);
    } else {
        return result;
    }
}

template<typename T>
bool encode_decode_roundtrip(T original_value) {
    static_assert(std::is_integral_v<T>, "encode_decode_roundtrip requires an integral type");

    // Prepare a simple byte buffer and adapt it for Hexi
    std::vector<std::uint8_t> storage;
    hexi::pmc::buffer_adaptor adaptor(storage);

    // Use a full binary_stream (reader + writer) on top of the buffer
    hexi::pmc::binary_stream stream(adaptor);

    // Encode using the writer interface
    encode_varint<T>(stream, original_value);

    // Reset read position of the buffer so we can read back the data.
    // buffer_adaptor exposes a "seek" or "set_read_pos" in Hexi; if not,
    // we can just construct a reader over the same adaptor with read_limit=0.
    // Here we construct a separate reader with the same underlying buffer.
    hexi::pmc::binary_stream_reader reader(adaptor);

    T decoded = decode_varint<T>(reader);

    return decoded == original_value;
}
