#include <hexi/hexi.h>
#include <string>
#include <string_view>

void write_string_prefixed_varint(hexi::binary_stream& stream, const std::string& str) {
    // Use Hexi's prefixed_varint adaptor to write the string with a varint length prefix
    stream << hexi::prefixed_varint(str);
}

std::string read_string_prefixed_varint(hexi::binary_stream& stream) {
    // Read into a std::string first; the adaptor uses a temporary string_view for extraction
    std::string result;
    std::string_view view;

    // Read the data using the prefixed_varint adaptor into a string_view
    stream >> hexi::prefixed_varint(view);

    // Copy the data from the view into the owning std::string
    result.assign(view.data(), view.size());

    return result;
}
