#include <hexi/shared.h>
#include <array>
#include <cstdint>

using namespace hexi::detail;

template<std::size_t Size>
constexpr auto create_filled_array(std::uint8_t value) {
    // Use Hexi's byte_type-compliant storage (std::byte) for the array
    std::array<std::byte, Size> result{};

    for (std::size_t i = 0; i < Size; ++i) {
        result[i] = static_cast<std::byte>(value);
    }

    return result;
}

bool verify_filled_array(const auto& arr, std::uint8_t expected_value) {
    const auto expected = static_cast<std::byte>(expected_value);

    for (const auto& elem : arr) {
        if (elem != expected) {
            return false;
        }
    }
    return true;
}
