#include <hexi/exception.h>
#include <hexi/pmc/binary_stream.h>
#include <hexi/pmc/buffer_adaptor.h>
#include <vector>
#include <cstdint>

struct ReadLimitInfo {
    std::size_t read_size;
    std::size_t total_read;
    std::size_t read_limit;
    bool occurred;
};

ReadLimitInfo catch_stream_read_limit() {
    ReadLimitInfo info{0, 0, 0, false};

    try {
        // Create a small buffer and a stream with a strict read limit,
        // then deliberately attempt to read past that limit to trigger
        // a stream_read_limit exception.
        std::vector<std::uint8_t> buffer(16, 0xFF);
        hexi::pmc::buffer_adaptor adaptor(buffer);
        // Set a read limit smaller than what we'll try to read
        hexi::pmc::binary_stream stream(adaptor, 4);

        // This read should exceed the read limit and throw
        std::uint8_t tmp[8];
        stream.read(tmp, sizeof(tmp));
    } catch (const hexi::stream_read_limit& ex) {
        info.read_size  = ex.read_size();
        info.total_read = ex.total_read();
        info.read_limit = ex.read_limit();
        info.occurred   = true;
    } catch (...) {
        // Any other exception: just leave occurred = false
    }

    return info;
}

ReadLimitInfo safe_read_with_limit_check(hexi::pmc::binary_stream& stream,
