#include <span>

struct CompactPacket {
    uint32_t packet_id;
    std::vector<std::string> tags;
    std::string data;
};

std::vector<uint8_t> serialize_compact_packet(const CompactPacket& packet) {
    // Backing buffer
    std::vector<uint8_t> buffer;

    // Create a Hexi buffer adaptor and binary stream for writing
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Write packet_id as a varint-encoded uint32_t
    stream << hexi::varint(packet.packet_id);

    // Write tags using prefixed_varint adaptor.
    // This will first write the number of tags as a varint, then each string
    // is written with its size encoded as a varint prefix.
    stream << hexi::prefixed_varint(packet.tags);

    // Write data string with its size encoded as varint prefix
    stream << hexi::prefixed_varint(packet.data);

    return buffer;
}

CompactPacket deserialize_compact_packet(const std::span<const uint8_t> buffer) {
    CompactPacket packet{};

    // Create a read-only adaptor and binary stream for reading
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Read packet_id as varint-encoded uint32_t
    stream >> hexi::varint(packet.packet_id);

    // Read tags vector using prefixed_varint
    stream >> hexi::prefixed_varint(packet.tags);

    // Read data string using prefixed_varint
    stream >> hexi::prefixed_varint(packet.data);

    return packet;
}
