    // Use a std::vector<uint8_t> as the underlying buffer
    std::vector<uint8_t> buffer;

    // Create a Hexi buffer adaptor and binary stream
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Serialize:
    // 1. header (uint16_t)
    // 2. data string (Hexi will include its length prefix)
    // 3. 16 bytes of 0x00 padding
    // 4. footer (uint32_t)
    stream(packet.header);
    stream(packet.data);
    stream.fill<16>(0x00);
    stream(packet.footer);

    return buffer;
}
