std::vector<uint8_t> write_and_read_data(const std::vector<uint8_t>& input_data) {
    // backing storage for the adaptors
    std::vector<std::uint8_t> buffer(input_data.size());

    // write the input_data into the buffer via buffer_write_adaptor
    hexi::pmc::buffer_write_adaptor write_adaptor(buffer);

    // ensure there is enough free space before writing
    if (write_adaptor.free() < input_data.size()) {
        // grow the backing buffer if needed and re-bind the adaptor
        buffer.resize(input_data.size());
        write_adaptor = hexi::pmc::buffer_write_adaptor(buffer);
    }

    write_adaptor.write(input_data.data(), input_data.size());

    // now read the data back out via buffer_read_adaptor
    hexi::pmc::buffer_read_adaptor read_adaptor(buffer);

    // check how much is readable
    const std::size_t readable = read_adaptor.size();
    std::vector<std::uint8_t> result(readable);

    if (readable > 0) {
        read_adaptor.read(result.data(), readable);
    }

    return result;
}

std::vector<uint8_t> peek_data_without_advancing(const std::vector<uint8_t>& buffer_data, std::size_t peek_size) {
    // create a read adaptor over the provided data
    hexi::pmc::buffer_read_adaptor read_adaptor(const_cast<std::vector<std::uint8_t>&>(buffer_data));

    // limit peek_size to what is actually available
    const std::size_t available = read_adaptor.size();
    const std::size_t to_peek = std::min(peek_size, available);

    std::vector<std::uint8_t> peeked(to_peek);

    if (to_peek == 0) {
        return peeked;
    }

    // use read_ptr() to get a pointer to the current read position
    const std::uint8_t* current_read_ptr = static_cast<const std::uint8_t*>(read_adaptor.read_ptr());

    // copy() to peek at the data without moving the read cursor
    read_adaptor.copy(peeked.data(), to_peek);

    // at this point, the adaptor's read position has not advanced;
    // we can confirm the pointer is still the same (not required, but shows usage)
    (void)current_read_ptr;

    // now actually consume the data using read()
    std::vector<std::uint8_t> consumed(to_peek);
    read_adaptor.read(consumed.data(), to_peek);

    // for this example we return the peeked data (which matches consumed)
    return peeked;
}
