```cpp
#include <hexi/pmc/buffer_read_adaptor.h>
#include <hexi/pmc/buffer_write_adaptor.h>
#include <vector>
#include <cstdint>
#include <algorithm>

std::size_t write_multiple_chunks(const std::vector<std::vector<uint8_t>>& chunks) {
    // Create a write buffer adaptor with some initial capacity. The actual
    // capacity type/behaviour depends on Hexi's implementation; here we
    // construct a growable buffer via the write adaptor's default constructor.
    hexi::pmc::buffer_write_adaptor adaptor;

    for (const auto& chunk : chunks) {
        const std::uint8_t* data = chunk.data();
        std::size_t remaining = chunk.size();

        while (remaining > 0) {
            // Check how much free space is currently available
            std::size_t available = adaptor.free();
            if (available == 0) {
                // If no space is available, let the adaptor grow its internal
                // buffer (implementation-defined; here we assume a helper).
                adaptor.reserve(remaining);
                available = adaptor.free();
                if (available == 0) {
                    // If the adaptor still reports no space, abort to avoid
                    // an infinite loop.
                    return adaptor.size();
                }
            }

            std::size_t to_write = std::min(available, remaining);
            adaptor.write(data, to_write);

            data      += to_write;
            remaining -= to_write;
        }
    }

    // Return the final size (total bytes written into the buffer)
    return adaptor.size();
}

std::vector<uint8_t> read_partial_data(const std::vector<uint8_t>& buffer, std::size_t chunk_size) {
    // Create a read adaptor over the provided buffer
    hexi::pmc::buffer_read_adaptor adaptor(buffer.data(), buffer.size());

    std::vector<std::uint8_t> result;
    result.reserve(buffer.size());

    while (adaptor.size() > 0) {
        std::size_t available = adaptor.size();
        std::size_t to_read   = std::min(available, chunk_size);

        std::vector<std::uint8_t> temp(to_read);
        adaptor.read(temp.data(), to_read);

        // Append what we just read to the result
        result.insert(result.end(), temp.begin(), temp.end());
    }

    return result;
}
