#include <hexi/pmc/buffer_read_adaptor.h>
#include <vector>
#include <cstdint>
#include <cstring>

struct Header {
    uint32_t magic;
    uint16_t version;
};

Header peek_header_without_reading(const std::vector<uint8_t>& buffer) {
    // Create a read-only adaptor over the input buffer
    hexi::pmc::buffer_read_adaptor adaptor(buffer);

    Header hdr { 0, 0 };

    // Peek at the header using copy(), which must NOT advance the read cursor
    adaptor.copy(&hdr, sizeof(Header));

    // Use read_ptr() to get a pointer to the current read position.
    // Since copy() does not consume data, the pointer should still be
    // pointing at the beginning of the buffer.
    const std::byte* ptr = adaptor.read_ptr();

    // Optionally verify that the data at read_ptr() matches what we just
    // copied into hdr, without advancing the cursor.
    Header verify { 0, 0 };
    std::memcpy(&verify, ptr, sizeof(Header));

    // In a real setting you might assert or otherwise verify this;
    // here we simply rely on the copy and return hdr.
    (void)verify; // suppress unused-variable warning if not used further

    return hdr;
}

std::vector<uint8_t> peek_then_conditionally_read(const std::vector<uint8_t>& buffer) {
    hexi::pmc::buffer_read_adaptor adaptor(buffer);
    std::vector<uint8_t> result;

    // If there's nothing to read, return empty result
    if (buffer.empty()) {
        return result;
    }

    // Peek at the first byte without consuming it
    uint8_t first = 0;
    adaptor.copy(&first, sizeof(first));

    // Example condition: only read further if first byte is non‑zero
    if (first != 0) {
        // Now we actually consume the data using read().
        // For demonstration, read the entire buffer contents.
        result.resize(buffer.size());
        adaptor.read(result.data(), result.size());
    } else {
        // Condition not met: do not consume anything, return empty result
        // (the adaptor's read cursor has not advanced because we only used copy()).
    }

    return result;
}
